type Cell = [number, number];

export function nextGeneration(cells: Cell[]): Cell[] {
  return cells.filter((cell) => {
    const neighborCount = countLiveNeighbors(cell, cells);
    return neighborCount === 2 || neighborCount === 3;
  });
}

function countLiveNeighbors(cell: Cell, cells: Cell[]): number {
  const [x, y] = cell;
  return cells.filter(([ox, oy]) => {
    const dx = Math.abs(ox - x);
    const dy = Math.abs(oy - y);
    return (dx === 1 || dy === 1 || dx === 1) && !(dx === 0 && dy === 0) && dx <= 1 && dy <= 1;
  }).length;
}

