type Cell = [number, number];

export function nextGeneration(cells: Cell[]): Cell[] {
  return cells.filter((cell) => survives(countLiveNeighbors(cell, cells)));
}

const MIN_NEIGHBORS_TO_SURVIVE = 2;
const MAX_NEIGHBORS_TO_SURVIVE = 3;

function survives(neighborCount: number): boolean {
  return (
    neighborCount === MIN_NEIGHBORS_TO_SURVIVE ||
    neighborCount === MAX_NEIGHBORS_TO_SURVIVE
  );
}

function countLiveNeighbors(cell: Cell, cells: Cell[]): number {
  return cells.filter((other) => isNeighbor(cell, other)).length;
}

function isNeighbor([x, y]: Cell, [ox, oy]: Cell): boolean {
  const dx = Math.abs(ox - x);
  const dy = Math.abs(oy - y);
  const isWithinRange = dx <= 1 && dy <= 1;
  const isSameCell = dx === 0 && dy === 0;
  return isWithinRange && !isSameCell;
}

