const NEIGHBORS_TO_REPRODUCE = 3;

export function nextGeneration(cells: Cell[]): Cell[] {
  const survivors = cells.filter((cell) =>
    survives(countLiveNeighbors(cell, cells))
  );
  const births = deadNeighbors(cells).filter(
    (cell) => countLiveNeighbors(cell, cells) === NEIGHBORS_TO_REPRODUCE
  );
  return [...survivors, ...births];
}

function deadNeighbors(cells: Cell[]): Cell[] {
  const candidates: Cell[] = [];
  for (const [x, y] of cells) {
    for (let dx = -1; dx <= 1; dx++) {
      for (let dy = -1; dy <= 1; dy++) {
        if (dx === 0 && dy === 0) continue;
        const candidate: Cell = [x + dx, y + dy];
        const isAlive = cells.some(([cx, cy]) => cx === candidate[0] && cy === candidate[1]);
        const alreadyAdded = candidates.some(
          ([cx, cy]) => cx === candidate[0] && cy === candidate[1]
        );
        if (!isAlive && !alreadyAdded) candidates.push(candidate);
      }
    }
  }
  return candidates;
}

